const responseText = $input.item.json.candidates[0].content.parts[0].text;
const scoredData = JSON.parse(responseText);
const raw = $node["Google Sheets Trigger (Raw Data)"].json;

// Extract district from searchString
let district = "Ari";
const searchStr = (raw.searchString || "").toLowerCase();
if (searchStr.includes("สยาม") || searchStr.includes("siam")) {
  district = "Siam";
} else if (searchStr.includes("อารีย์") || searchStr.includes("ari")) {
  district = "Ari";
} else if (searchStr.includes("ทองหล่อ") || searchStr.includes("thonglor")) {
  district = "Thonglor";
} else if (searchStr.includes("อโศก") || searchStr.includes("asoke")) {
  district = "Asoke";
} else if (searchStr.includes("พร้อมพงษ์") || searchStr.includes("phrom")) {
  district = "Phrom Phong";
}

return {
  json: {
    placeId: raw.placeId || "",
    title: raw.title || "",
    district: district,
    category: raw.categoryName || "ร้านอาหาร",
    rating: parseFloat(raw.totalScore) || 3.5,
    reviewsCount: parseInt(raw.reviewsCount) || 0,
    priceRange: raw.price || "฿200-400",
    address: raw.address || "",
    website: raw.website || "",
    phone: raw.phone || "",
    openingHours: raw.openingHours || "",
    url: raw.url || "",
    ratingScore: parseFloat(scoredData.ratingScore) || 0,
    groupSuitabilityScore: parseFloat(scoredData.groupSuitabilityScore) || 0,
    priceSuitabilityScore: parseFloat(scoredData.priceSuitabilityScore) || 0,
    travelConvenienceScore: parseFloat(scoredData.travelConvenienceScore) || 0,
    dataCompletenessScore: parseFloat(scoredData.dataCompletenessScore) || 0,
    uniquenessScore: parseFloat(scoredData.uniquenessScore) || 0,
    totalScore: parseFloat(scoredData.totalScore) || 0,
    suitabilityNotes: scoredData.suitabilityNotes || "คำนวณคะแนนผ่าน Gemini"
  }
};
